# 测试 ArXivTool 的代码示例

以下是一个完整的测试代码，包含单元测试和集成测试：

```python
import pytest
import asyncio
from unittest.mock import Mock, patch, MagicMock, AsyncMock
from datetime import datetime

from verl.tools.arxiv_tool import ArXivTool
from verl.tools.schemas import OpenAIFunctionToolSchema, ToolResponse


class TestArXivTool:
    """ArXivTool 测试类"""

    @pytest.fixture
    def mock_config(self):
        """模拟配置"""
        return {
            "ip": "127.0.0.1",
            "port": "8000",
            "model_name": "Qwen/Qwen3-Embedding-8B",
            "api_key": "test_key",
            "index_name": "test-arxiv",
            "es_url": "https://localhost:9200",
            "ca_certs": "config/certs/http_ca.crt",
            "elastic_password": "test_password",
            "fetch_k": 60,
            "k": 5,
            "max_content_length": 8192,
        }

    @pytest.fixture
    def mock_tool_schema(self):
        """模拟工具 schema"""
        return OpenAIFunctionToolSchema(
            type="function",
            function={
                "name": "arxiv_search",
                "description": "Search arxiv papers",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "queries": {
                            "type": "array",
                            "items": {"type": "string"},
                            "description": "Search queries"
                        },
                        "end_date": {
                            "type": "string",
                            "description": "End date for search"
                        }
                    },
                    "required": ["queries", "end_date"]
                }
            }
        )

    @pytest.fixture
    def mock_documents(self):
        """模拟 Elasticsearch 返回的文档"""
        mock_doc1 = Mock()
        mock_doc1.page_content = "This is a summary of paper 1 about machine learning."
        mock_doc1.metadata = {
            "source": "2301.12345.pdf",
            "authors": "John Doe, Jane Smith",
            "title": "Machine Learning Advances",
            "submit_time": "2023-01-15T00:00:00"
        }

        mock_doc2 = Mock()
        mock_doc2.page_content = "This is a summary of paper 2 about deep learning."
        mock_doc2.metadata = {
            "source": "2302.67890.pdf",
            "authors": "Alice Brown",
            "title": "Deep Learning Methods",
            "submit_time": "2023-02-20T00:00:00"
        }

        return [mock_doc1, mock_doc2]

    @patch('verl.tools.arxiv_tool.Elasticsearch')
    @patch('verl.tools.arxiv_tool.OpenAIEmbeddings')
    @patch('verl.tools.arxiv_tool.ElasticsearchStore')
    def test_init(self, mock_es_store, mock_embeddings, mock_es_client, 
                  mock_config, mock_tool_schema):
        """测试初始化"""
        # 设置 mock
        mock_es_client.return_value.info.return_value = {"version": "8.0"}

        # 创建实例
        tool = ArXivTool(mock_config, mock_tool_schema)

        # 验证
        assert tool._instance_dict == {}
        assert tool.fetch_k == 60
        assert tool.k == 5
        assert tool.max_char_to_include == 8192
        mock_embeddings.assert_called_once()
        mock_es_client.assert_called_once()
        mock_es_store.assert_called_once()

    @patch('verl.tools.arxiv_tool.Elasticsearch')
    @patch('verl.tools.arxiv_tool.OpenAIEmbeddings')
    @patch('verl.tools.arxiv_tool.ElasticsearchStore')
    def test_get_openai_tool_schema(self, mock_es_store, mock_embeddings, 
                                    mock_es_client, mock_config, mock_tool_schema):
        """测试获取工具 schema"""
        tool = ArXivTool(mock_config, mock_tool_schema)
        schema = tool.get_openai_tool_schema()

        assert schema == mock_tool_schema
        assert schema.function["name"] == "arxiv_search"

    @pytest.mark.asyncio
    @patch('verl.tools.arxiv_tool.Elasticsearch')
    @patch('verl.tools.arxiv_tool.OpenAIEmbeddings')
    @patch('verl.tools.arxiv_tool.ElasticsearchStore')
    async def test_create(self, mock_es_store, mock_embeddings, mock_es_client,
                         mock_config, mock_tool_schema):
        """测试创建实例"""
        tool = ArXivTool(mock_config, mock_tool_schema)

        # 测试不指定 instance_id
        instance_id1, response1 = await tool.create()
        assert instance_id1 in tool._instance_dict
        assert tool._instance_dict[instance_id1]["response"] == ""
        assert tool._instance_dict[instance_id1]["reward"] == 0.0
        assert isinstance(response1, ToolResponse)

        # 测试指定 instance_id
        custom_id = "custom_test_id"
        instance_id2, response2 = await tool.create(instance_id=custom_id)
        assert instance_id2 == custom_id
        assert custom_id in tool._instance_dict

    @pytest.mark.asyncio
    @patch('verl.tools.arxiv_tool.Elasticsearch')
    @patch('verl.tools.arxiv_tool.OpenAIEmbeddings')
    @patch('verl.tools.arxiv_tool.ElasticsearchStore')
    async def test_execute_success(self, mock_es_store, mock_embeddings, 
                                   mock_es_client, mock_config, mock_tool_schema,
                                   mock_documents):
        """测试成功执行查询"""
        tool = ArXivTool(mock_config, mock_tool_schema)
        tool.vector_store.similarity_search = Mock(return_value=mock_documents)

        # 创建实例
        instance_id, _ = await tool.create()

        # 执行查询
        parameters = {
            "queries": ["machine learning", "deep learning"],
            "end_date": "2023-12-31"
        }

        response, reward, metadata = await tool.execute(instance_id, parameters)

        # 验证
        assert isinstance(response, ToolResponse)
        assert "Machine Learning Advances" in response.text
        assert "Deep Learning Methods" in response.text
        assert "https://arxiv.org/abs/2301.12345" in response.text
        assert reward == 0.0
        assert metadata == {}

        # 验证 similarity_search 被调用
        assert tool.vector_store.similarity_search.call_count == 2

    @pytest.mark.asyncio
    @patch('verl.tools.arxiv_tool.Elasticsearch')
    @patch('verl.tools.arxiv_tool.OpenAIEmbeddings')
    @patch('verl.tools.arxiv_tool.ElasticsearchStore')
    async def test_execute_no_queries(self, mock_es_store, mock_embeddings,
                                     mock_es_client, mock_config, mock_tool_schema):
        """测试没有查询的情况"""
        tool = ArXivTool(mock_config, mock_tool_schema)
        instance_id, _ = await tool.create()

        parameters = {
            "queries": [],
            "end_date": "2023-12-31"
        }

        with pytest.raises(ValueError, match="No arxiv queries"):
            await tool.execute(instance_id, parameters)

    @pytest.mark.asyncio
    @patch('verl.tools.arxiv_tool.Elasticsearch')
    @patch('verl.tools.arxiv_tool.OpenAIEmbeddings')
    @patch('verl.tools.arxiv_tool.ElasticsearchStore')
    async def test_release(self, mock_es_store, mock_embeddings, mock_es_client,
                          mock_config, mock_tool_schema):
        """测试释放实例"""
        tool = ArXivTool(mock_config, mock_tool_schema)

        # 创建实例
        instance_id, _ = await tool.create()
        assert instance_id in tool._instance_dict

        # 释放实例
        await tool.release(instance_id)
        assert instance_id not in tool._instance_dict

    @patch('verl.tools.arxiv_tool.Elasticsearch')
    @patch('verl.tools.arxiv_tool.OpenAIEmbeddings')
    @patch('verl.tools.arxiv_tool.ElasticsearchStore')
    def test_sanitize(self, mock_es_store, mock_embeddings, mock_es_client,
                     mock_config, mock_tool_schema, mock_documents):
        """测试文档清理方法"""
        tool = ArXivTool(mock_config, mock_tool_schema)

        result = tool.sanitize(mock_documents)

        # 验证格式
        assert "--- SOURCE 1: Machine Learning Advances ---" in result
        assert "--- arxiv_ID https://arxiv.org/abs/2301.12345 ---" in result
        assert "--- authors John Doe, Jane Smith ---" in result
        assert "SUMMARY:" in result
        assert "This is a summary of paper 1" in result

        # 验证长度限制
        assert len(result) <= tool.max_char_to_include

    @patch('verl.tools.arxiv_tool.Elasticsearch')
    @patch('verl.tools.arxiv_tool.OpenAIEmbeddings')
    @patch('verl.tools.arxiv_tool.ElasticsearchStore')
    def test_sanitize_duplicate_removal(self, mock_es_store, mock_embeddings,
                                       mock_es_client, mock_config, mock_tool_schema):
        """测试去重功能"""
        tool = ArXivTool(mock_config, mock_tool_schema)

        # 创建重复的文档
        mock_doc = Mock()
        mock_doc.page_content = "Test content"
        mock_doc.metadata = {
            "source": "2301.12345.pdf",
            "authors": "Test Author",
            "title": "Test Title",
        }

        duplicate_docs = [mock_doc, mock_doc]
        result = tool.sanitize(duplicate_docs)

        # 验证只包含一次
        assert result.count("https://arxiv.org/abs/2301.12345") == 1
        assert result.count("Test Title") == 1

    @pytest.mark.asyncio
    @patch('verl.tools.arxiv_tool.Elasticsearch')
    @patch('verl.tools.arxiv_tool.OpenAIEmbeddings')
    @patch('verl.tools.arxiv_tool.ElasticsearchStore')
    async def test_execute_with_date_filter(self, mock_es_store, mock_embeddings,
                                           mock_es_client, mock_config, 
                                           mock_tool_schema, mock_documents):
        """测试日期过滤功能"""
        tool = ArXivTool(mock_config, mock_tool_schema)

        # 创建一个捕获调用参数的 mock
        call_args_list = []
        def mock_similarity_search(*args, **kwargs):
            call_args_list.append(kwargs)
            return mock_documents

        tool.vector_store.similarity_search = mock_similarity_search

        instance_id, _ = await tool.create()

        parameters = {
            "queries": ["test query"],
            "end_date": "2023-06-30"
        }

        await tool.execute(instance_id, parameters)

        # 验证日期过滤器
        assert len(call_args_list) == 1
        filter_param = call_args_list[0]['filter']
        assert len(filter_param) == 1
        assert 'range' in filter_param[0]
        assert 'metadata.submit_time' in filter_param[0]['range']


